import Foundation

let questions6: [QuizQuestion] = [
QuizQuestion(id:381,question:"O que foi o Concílio de Jerusalém em Atos 15?",options:["Uma reunião política","A primeira assembleia da Igreja para decidir se gentios precisavam","Uma festa judaica","O julgamento de Paulo"],correctIndex:1,explanation:"Atos 15 registra o Concílio de Jerusalém onde a Igreja decidiu que os gentios não precisavam se circuncidar para ser salvos — apenas a graça de Cristo.",reference:"Atos 15:11",category:.atos,propheticMeaning:"O Concílio de Jerusalém protegeu o evangelho puro da graça, mostrando que o Espírito Santo guia a Igreja em assembleias conciliares para preservar a verdade."),
QuizQuestion(id:382,question:"O que Paulo quer dizer com 'novo homem' em Efésios 4:24?",options:["Um novo ser humano físico","A nova identidade e natureza recriada em Cristo","Uma segunda chance na vida","Um cargo novo na Igreja"],correctIndex:1,explanation:"Ef 4:24: 'Revesti o novo homem, criado segundo Deus em justiça e santidade procedentes da verdade.' A nova identidade em Cristo deve ser 'vestida' pela prática.",reference:"Efésios 4:22-24",category:.atos,propheticMeaning:"'Reves-ti o novo homem' está no aoristo grego — aconteceu na conversão, mas Ef 4 mostra que precisa ser continuamente afirmado na prática. A identidade precede a prática."),
QuizQuestion(id:383,question:"Quem foi Barnabé na Igreja primitiva?",options:["Um dos doze apóstolos","Companheiro de Paulo nas viagens missionárias","Um sacerdote em Jerusalém","O cunhado de Pedro"],correctIndex:1,explanation:"Barnabé (At 4:36) era levita cipriota chamado de 'filho de consolação', parceiro de Paulo na primeira viagem missionária e defensor de Paulo diante dos apóstolos.",reference:"Atos 4:36; 13:2",category:.atos,propheticMeaning:"Barnabé introduzindo Paulo à Igreja quando todos o temiam (At 9:27) é modelo da encorajamento — o ministério de consolação que acolhe e restaura os rejeitados."),
QuizQuestion(id:384,question:"O que Paulo ensina sobre a oração em 1 Timóteo 2:1-2?",options:["Orar apenas pelos crentes","'Exorto que se façam súplicas, orações","Orar em silêncio apenas","Orar apenas em línguas"],correctIndex:1,explanation:"1 Timóteo 2:1-2 instrui oração por toda autoridade civil — reis, governadores — para que possamos viver em paz e tranquilidade.",reference:"1 Timóteo 2:1-2",category:.atos,propheticMeaning:"Orar pelos governantes (mesmo pagãos e perseguidores) é ato de fé na soberania de Deus sobre toda autoridade — 'porque Deus quer que todos os homens se salvem' (1 Tm 2:4)."),
QuizQuestion(id:385,question:"Qual é o tema da carta de 2 Timóteo?",options:["Organização da Igreja","O testamento final de Paulo na prisão: perseverar no evangelho","Os dons espirituais","As regras do casamento"],correctIndex:1,explanation:"2 Timóteo é a última carta de Paulo, escrita antes de sua execução — um legado para Timóteo e a Igreja: perseverar no evangelho e guardar a sana doutrina.",reference:"2 Timóteo 4:6-8",category:.atos,propheticMeaning:"Paulo dizendo 'combati o bom combate, acabei a carreira, guardei a fé' (2 Tm 4:7) é o modelo de vida cristã fiel até o fim — não o sucesso mundano mas a fidelidade até a morte."),
QuizQuestion(id:386,question:"O que Tito 3:5 ensina sobre a salvação?",options:["Salvos pelas obras","'Salvou-nos, não pelas obras de justiça que tínhamos feito","Salvos pela mistura de fé e obras","Salvos pela circuncisão"],correctIndex:1,explanation:"Tito 3:5 é uma das mais claras declarações da salvação pela graça: não por obras mas pela misericórdia, lavagem da regeneração e renovação do Espírito.",reference:"Tito 3:5",category:.atos,propheticMeaning:"A 'lavagem da regeneração' combina batismo (sinal externo) e regeneração pelo Espírito (realidade interna) — a nova criação que Deus opera, não produto humano."),
QuizQuestion(id:387,question:"Qual é o argumento central de Hebreus 10 sobre o sacrifício de Cristo?",options:["Cristo precisava morrer repetidas vezes","'Com uma só oferta aperfeiçoou para sempre os que estão sendo...","Cristo apenas exemplificou o sacrifício","Os sacrifícios do AT ainda são necessários"],correctIndex:1,explanation:"Hebreus 10:14: 'Com uma só oferta aperfeiçoou para sempre os que estão sendo santificados.' O sacrifício de Cristo foi único e suficiente — contrário às repetidas ofertas levíticas.",reference:"Hebreus 10:14",category:.atos,propheticMeaning:"'Uma vez para sempre' (ephapax) é a palavra-chave de Hebreus — o sacrifício definitivo que não precisa repetição, tornando a Missa Católica e qualquer sacrifício posterior teologicamente problemáticos."),
QuizQuestion(id:388,question:"O que Pedro ensina sobre o crescimento espiritual em 2 Pedro 1:5-7?",options:["Apenas crer é suficiente","Acrescentar à fé: virtude, conhecimento, domínio próprio","Crescer apenas pela oração","Crescer apenas pela leitura da Bíblia"],correctIndex:1,explanation:"2 Pedro 1:5-7 lista sete qualidades a serem acrescentadas à fé — um processo progressivo de crescimento na semelhança com Cristo.",reference:"2 Pedro 1:5-7",category:.atos,propheticMeaning:"As sete qualidades formam uma escada de crescimento espiritual — cada uma construindo sobre a anterior, mostrando que a fé salvadora não é estática mas viva e crescente."),
QuizQuestion(id:389,question:"O que João ensina sobre o anticristo em 1 João 4:2-3?",options:["O anticristo é apenas um indivíduo futuro","Todo espírito que não confessa que Jesus Cristo veio em carne é","O anticristo não existe ainda","O anticristo é Satanás"],correctIndex:1,explanation:"1 João 4:2-3: o espírito que não confessa a encarnação real de Cristo é espírito do anticristo — João alerta para uma atitude herética já presente em sua época (docetismo).",reference:"1 João 4:2-3",category:.atos,propheticMeaning:"O 'espírito do anticristo' é qualquer ensino que nega a plena humanidade ou plena divindade de Cristo — as duas heresias mais antigas: docetismo (negou humanidade) e adocionismo (negou divindade)."),
QuizQuestion(id:390,question:"Qual é o tema do livro de Atos dos Apóstolos?",options:["A vida de Pedro","O movimento do Espírito Santo expandindo a Igreja de Jerusalém até os","As viagens de Paulo apenas","As cartas dos apóstolos"],correctIndex:1,explanation:"Atos 1:8 define o tema: 'recebereis poder... e sereis minhas testemunhas em Jerusalém, em toda a Judéia, Samaria e até aos confins da terra.' O livro mostra esse cumprimento.",reference:"Atos 1:8",category:.atos,propheticMeaning:"Atos é o livro da missão guiada pelo Espírito — o terceiro livro da Trindade: Lucas escreve o Evangelho do Filho, e Atos como o evangelho do Espírito Santo em ação."),
QuizQuestion(id:391,question:"Quem foi Apollos no NT?",options:["Um imperador romano","Um judeu alexandrino eloquente e versado nas Escrituras que pregou em","Um adversário de Paulo","Um dos doze apóstolos"],correctIndex:1,explanation:"Apollos (At 18:24-28) era judeu alexandrino, eloquente e fervoroso, que conhecia apenas o batismo de João. Priscila e Áquila o instruíram mais completamente.",reference:"Atos 18:24-28",category:.atos,propheticMeaning:"Apollos recebendo instrução de leigos (Priscila e Áquila) mostra que o crescimento espiritual exige humildade para aprender de qualquer pessoa que Deus use — mesmo um orador talentoso."),
QuizQuestion(id:392,question:"Qual é a profecia de João sobre o lago de fogo?",options:["O lago de fogo é simbólico sem realidade","'A morte e o inferno foram lançados no lago de fogo. Esta é a segunda","O lago de fogo é purgatório","Todos serão eventualmente salvos do lago de fogo"],correctIndex:1,explanation:"Apocalipse 20:14-15: a morte, o Hades, o diabo e os que não estão no livro da vida serão lançados no lago de fogo — a segunda morte, separação eterna de Deus.",reference:"Apocalipse 20:10,14-15",category:.atos,propheticMeaning:"A segunda morte é a morte eterna — separação permanente de Deus, a fonte de toda vida. Cristo, ao vencer a primeira morte (física), liberta os crentes da segunda (Mt 10:28; Ap 2:11)."),
QuizQuestion(id:393,question:"Qual é a 'nova canção' em Apocalipse 5?",options:["O Halleluia cósmico","'Digno és de tomar o livro e abrir os seus selos","O hino criacional","O cântico de Moisés"],correctIndex:1,explanation:"Apocalipse 5:9-10: as criaturas e anciãos cantam a nova canção sobre a redenção do Cordeiro — que comprou com sangue pessoas de toda nação para reinar na terra.",reference:"Apocalipse 5:9-10",category:.atos,propheticMeaning:"A 'nova canção' cumpre o Salmo 149:1 — nova porque celebra a nova criação e nova aliança inauguradas pelo Cordeiro imolado e ressurreto, exaltado acima de toda autoridade."),
QuizQuestion(id:394,question:"O que significa o 'Cordeiro imolado' em Apocalipse?",options:["Um animal sacrificado no templo","Cristo crucificado e ressurreto que agora reina","Um símbolo sem realidade","A Igreja sofrendo perseguição"],correctIndex:1,explanation:"Apocalipse 5:6: o Cordeiro 'estava em pé, como que morto' — crucificado mas ressurreto, reunindo em si fraqueza redentora e poder soberano.",reference:"Apocalipse 5:6",category:.atos,propheticMeaning:"O Cordeiro imolado recebendo toda a honra e poder (Ap 5:12) é a subversão suprema de todos os valores mundanos: a vítima tornou-se Rei, a fraqueza tornou-se poder, a morte tornou-se vida."),
QuizQuestion(id:395,question:"Qual é a diferença entre o 'arrebatamento' (pré-tribulação) e a 'segunda vinda'?",options:["São a mesma coisa","O arrebatamento pré-trib é quando Cristo vem pelos crentes","O arrebatamento aconteceu","Apenas a segunda vinda é bíblica segundo todos..."],correctIndex:1,explanation:"Há diferentes posições: pré-tribucionistas distinguem o arrebatamento (1 Ts 4:16-17) da segunda vinda (Ap 19); pós-tribucionistas veem como um evento único.",reference:"1 Tessalonicenses 4:16-17; Apocalipse 19:11",category:.atos,propheticMeaning:"Independente da posição, a esperança é certa: 'O próprio Senhor descerá do céu' (1 Ts 4:16) — Cristo virá pessoalmente e todos que são dele se reúnem com ele."),
QuizQuestion(id:396,question:"O que Paulo ensina sobre tentação em 1 Coríntios 10:13?",options:["Toda tentação é insuperável","'Não viestes tentação que não seja humana","Devemos evitar toda situação difícil","A tentação vem apenas do diabo"],correctIndex:1,explanation:"1 Co 10:13: Deus não permite tentação além do que suportamos e sempre provê o escape — a fidelidade de Deus é nossa garantia na tentação.",reference:"1 Coríntios 10:13",category:.atos,propheticMeaning:"A promessa do 'escape' (ekbasis) não é sempre remoção da tentação mas capacidade de suportá-la — Cristo que foi tentado em tudo (Hb 4:15) é nossa força no meio da provação."),
QuizQuestion(id:397,question:"O que significa 'Maranata' no final de 1 Coríntios?",options:["Uma saudação em hebraico","'O Senhor vem' ou 'Vem, Senhor'","Uma bênção sacerdotal","Uma maldição sobre os inimigos"],correctIndex:1,explanation:"'Maranata' (1 Co 16:22) é a oração aramaica da Igreja primitiva: 'Senhor, vem!' — a mais antiga oração cristã conhecida, expressando ansiedade pela volta de Cristo.",reference:"1 Coríntios 16:22; Apocalipse 22:20",category:.atos,propheticMeaning:"'Maranata' e 'Vem, Senhor Jesus' (Ap 22:20) formam a moldura da esperança cristã — a Igreja vive entre o 'já' da redenção e o 'ainda não' da consumação, orando para que Cristo venha."),
QuizQuestion(id:398,question:"O que Paulo ensina sobre dar em 2 Coríntios 9:7?",options:["Dar o mínimo de 10%","'Cada um dê como propuser no coração","Dar apenas na Igreja local","Dar apenas quando Rico"],correctIndex:1,explanation:"2 Co 9:7: dar deve ser voluntário, alegre e proporcional — não por compulsão ou tristeza. Deus ama o 'doador alegre' (hilaros — hilarante!).",reference:"2 Coríntios 9:7",category:.atos,propheticMeaning:"O doador alegre reflete o coração de Deus que 'deu seu Filho' (Jo 3:16) — generosidade como participação no caráter divino, não obrigação religiosa."),
QuizQuestion(id:399,question:"O que João diz sobre ver a Deus em 1 João 3:2?",options:["Ninguém jamais verá a Deus","'Agora somos filhos de Deus","Veremos a Deus apenas espiritualmente","Apenas os profetas verão a Deus"],correctIndex:1,explanation:"1 João 3:2: na consumação seremos semelhantes a Cristo porque o veremos como ele é — a visão beatífica e a glorificação final do crente.",reference:"1 João 3:2",category:.atos,propheticMeaning:"'Ver a Deus' (a visão beatífica) é o cumprimento de Mateus 5:8: 'bem-aventurados os puros de coração, porque eles verão a Deus.' Cristo ao nos purificar nos capacita para essa visão eterna."),
QuizQuestion(id:400,question:"Qual é o ensinamento de Jesus sobre os 'falsos profetas' em Mateus 7:15-20?",options:["Não existem falsos profetas","'Pelos seus frutos os conhecereis'","Os falsos profetas são facilmente identificáveis","Apenas os apóstolos podiam discernir"],correctIndex:1,explanation:"Mateus 7:15-20: Jesus alerta para falsos profetas em roupagem de ovelhas — identificados pelo fruto (caráter), não pela aparência ou dons.",reference:"Mateus 7:15-20",category:.geral,propheticMeaning:"O critério do fruto protege contra o entusiasmo espiritual ingênuo — milagres e dons não autenticam (Mt 7:22-23), mas o caráter transformado pelo Espírito Santo sim."),
QuizQuestion(id:401,question:"O que Paulo diz sobre a 'obra boa' em Efésios 2:10?",options:["Obras nos salvam","'Somos criação de Deus em Cristo Jesus para boas obras","Obras são opcionais","Obras são apenas para líderes"],correctIndex:1,explanation:"Ef 2:10: embora salvos por graça (v.8-9), somos criados para boas obras — Deus preparou de antemão os caminhos de serviço para cada crente.",reference:"Efésios 2:8-10",category:.geral,propheticMeaning:"A sequência de Ef 2: 1) salvos por graça (v.8-9), 2) criados para obras (v.10) — Paulo responde de antemão a quem pergunta 'então podemos pecar à vontade?' com um não categórico."),
QuizQuestion(id:402,question:"O que é a 'intercessão' de Cristo segundo Hebreus 7:25?",options:["Jesus ainda está morrendo pela Igreja","'Jesus pode salvar completamente os que por ele se chegam a Deus","Jesus intercede apenas pelos apóstolos","A intercessão de Cristo terminou na ressurreição"],correctIndex:1,explanation:"Hebreus 7:25: Cristo 'vive sempre para interceder' pelos que vêm a Deus por ele — sua intercessão contínua é nossa segurança.",reference:"Hebreus 7:25",category:.geral,propheticMeaning:"Cristo intercedendo permanentemente (Rm 8:34) garante que nenhuma acusação do diabo nos condenará — ele que morreu por nós é o mesmo que intercede por nós diante do Pai."),
QuizQuestion(id:403,question:"O que João ensina sobre 'permanecer em Cristo' em João 15?",options:["Visitar a Igreja regularmente","'Permanecei em mim e eu em vós. Como o ramo não pode dar fruto de si","Lembrar de Jesus de vez em quando","Seguir todos os rituais"],correctIndex:1,explanation:"João 15:4-5: a videira e os ramos — fora de Cristo nada podemos fazer. Permanecer nele é a condição do fruto.",reference:"João 15:4-5",category:.geral,propheticMeaning:"'Sem mim nada podeis fazer' é a mais radical negação da auto-suficiência humana na ética cristã — todo fruto espiritual vem da conexão viva com Cristo, não do esforço próprio."),
QuizQuestion(id:404,question:"O que Paulo diz sobre transformação em Romanos 12:2?",options:["Siga os costumes do mundo","'Não vos conformeis com este século","Transformação não é possível","Transformação é apenas externa"],correctIndex:1,explanation:"Rm 12:2: não conformidade com o mundo mas transformação (metamorfose) pela renovação da mente — processo que discerne e pratica a vontade de Deus.",reference:"Romanos 12:2",category:.geral,propheticMeaning:"'Metamorphousthe' (metamorfose) é o mesmo termo da Transfiguração — o crente passa pela transformação progressiva que antecipa a glorificação final em 2 Co 3:18."),
QuizQuestion(id:405,question:"O que é o 'corpo de Cristo' na teologia de Paulo?",options:["O corpo físico de Jesus","A Igreja: comunidade de crentes unidos a Cristo e entre si","Apenas os apóstolos","O pão da Ceia do Senhor somente"],correctIndex:1,explanation:"1 Coríntios 12:12-27: a Igreja é o corpo de Cristo — Cristo é a cabeça (Ef 1:22-23), os crentes são os membros com funções diversas mas essenciais.",reference:"1 Coríntios 12:12-27",category:.geral,propheticMeaning:"O corpo de Cristo sendo a Igreja revela que Cristo continua sua presença e missão no mundo por meio da comunidade de crentes — a encarnação continua de forma corporativa."),
QuizQuestion(id:406,question:"Qual é a promessa de Isaías 53:11?",options:["'Ele será glorificado entre os reis'","'Pela sua sabedoria o meu servo justo justificará a muitos e sobre si","'Ele governará as nações'","'Ele viverá para sempre'"],correctIndex:1,explanation:"Isaías 53:11: o Servo Sofredor justificará muitos ao carregar suas iniquidades — a expiação substitutiva e vicária profetizada com precisão.",reference:"Isaías 53:11",category:.profetas,propheticMeaning:"'Justificará a muitos' usa o mesmo vocabulário jurídico de Paulo em Romanos 3:24 — a justificação de pecadores pela obra do Servo é o eixo da soteriologia bíblica."),
QuizQuestion(id:407,question:"Qual é a promessa de Ezequiel 36:26-27?",options:["Que Israel retornará à terra","'Dar-vos-ei coração novo e espírito novo... porei o meu Espírito","Que o templo será reconstruído","Que a lei de Moisés será ampliada"],correctIndex:1,explanation:"Ezequiel 36:26-27 profetiza a transformação interior da nova aliança: coração novo, espírito novo e o próprio Espírito de Deus habitando e guiando.",reference:"Ezequiel 36:26-27",category:.profetas,propheticMeaning:"Esta promessa é o fundamento da nova aliança (Jr 31:33) e foi cumprida no Pentecostes — o Espírito Santo transformando de dentro, não lei externa imposta de fora."),
QuizQuestion(id:408,question:"Qual é a diferença entre profecia 'já cumprida' e 'ainda não cumprida' na Bíblia?",options:["Toda profecia já foi cumprida","Algumas profecias se cumpriram historicamente (Babilônia, exílio","Nenhuma profecia se cumpriu ainda","Apenas profecias do AT tinham cumprimento"],correctIndex:1,explanation:"A escatologia bíblica tem a tensão 'já/ainda não': o Reino veio (já) mas ainda não em plenitude. Profecias do Messias têm cumprimento parcial na primeira vinda e pleno na segunda.",reference:"Atos 3:18-21",category:.profetas,propheticMeaning:"A tensão 'já/ainda não' é o nervo da esperança cristã — vivemos entre a ressurreição de Cristo (garantia) e nossa própria ressurreição (consumação), participando do Reino que veio mas que ainda não veio em plenitude."),
QuizQuestion(id:409,question:"O que foi a diáspora judaica?",options:["A entrada em Canaã","A dispersão dos judeus fora da terra de Israel","A divisão do reino","A destruição do templo apenas"],correctIndex:1,explanation:"Diáspora (dispersão) refere-se aos judeus vivendo fora de Israel — começou com os exílios assírio e babilônico e expandiu-se no período greco-romano.",reference:"Deuteronômio 28:64; João 7:35",category:.profetas,propheticMeaning:"A diáspora providencialmente preparou o mundo para o evangelho — sinagogas por todo o Império Romano forneceram o ponto de entrada missionário de Paulo: pessoas que conheciam as Escrituras do AT."),
QuizQuestion(id:410,question:"O que foi o exílio babilônico e quanto tempo durou?",options:["30 anos","70 anos (605-538 a.C.)","100 anos","40 anos"],correctIndex:1,explanation:"O exílio babilônico durou 70 anos (Jr 25:11-12), começando com as deportações de Nabucodonosor (605 a.C.) e terminando com o decreto de Ciro (538 a.C.).",reference:"Jeremias 25:11-12; Daniel 9:2",category:.profetas,propheticMeaning:"Jeremias profetizando 70 anos de exílio (Jr 25:11) foi cumprido com precisão — Daniel reconheceu o cumprimento e orou pela restauração (Dn 9:2), modelo de interpretar e interceder pelas profecias."),
QuizQuestion(id:411,question:"Quem foi Ciro, o Grande, e qual seu papel na profecia bíblica?",options:["Um profeta de Israel","O rei persa que decretou o retorno dos judeus do exílio","Um rei de Judá","O conquistador de Babilônia apenas"],correctIndex:1,explanation:"Isaías 45:1 nomeia Ciro como 'meu ungido' que libertará Israel — escrito 150 anos antes de Ciro nascer. Ele emitiu o decreto de retorno em 538 a.C.",reference:"Isaías 44:28; 45:1; Esdras 1:1-4",category:.profetas,propheticMeaning:"Isaías nomeando Ciro 150 anos antes é uma das provas mais extraordinárias da inspiração profética — somente Deus pode nomear um rei antes de nascer."),
QuizQuestion(id:412,question:"O que profetizou Isaías 11 sobre o reinado do Messias?",options:["Que o Messias reinaria apenas em Israel","Um rebento da raiz de Jessé sobre o qual repousará o Espírito","Que o Messias seria apenas sacerdote","Que o Messias destruiria todos os inimigos imediatamente"],correctIndex:1,explanation:"Isaías 11:1-9 profetiza o 'rebento de Jessé' — o Messias cheio do Espírito — estabelecendo um reino de paz universal onde os antagonismos da criação caída serão revertidos.",reference:"Isaías 11:1-9",category:.profetas,propheticMeaning:"'O lobo habitará com o cordeiro' (Is 11:6) descreve a nova criação onde o pecado não mais perverteu os relacionamentos — cumprimento pleno aguardado na restauração final de todas as coisas (At 3:21)."),
QuizQuestion(id:413,question:"Qual é a profecia de Isaías 61:1-2 e como Jesus a interpretou?",options:["Uma profecia sobre Ciro","'O Espírito do Senhor está sobre mim'","Uma profecia sobre o exílio","Uma profecia sobre Israel retornando"],correctIndex:1,explanation:"Jesus leu Isaías 61:1-2 na sinagoga de Nazaré e declarou: 'Hoje se cumpriu esta Escritura nos vossos ouvidos' — identificando-se como o ungido do Espírito para libertar cativos.",reference:"Isaías 61:1-2; Lucas 4:18-21",category:.profetas,propheticMeaning:"Jesus parou de ler na metade de Is 61:2, omitindo 'o dia da vingança' — indicando que a primeira vinda é o 'ano aceitável' (graça) e a segunda vinda é o 'dia da vingança' (juízo)."),
QuizQuestion(id:414,question:"Qual é o 'sofrimento vicário' em Isaías 53?",options:["Sofrimento que você merece","Sofrimento em lugar de outro","Sofrimento para ganhar mérito","Sofrimento como castigo divino para si mesmo"],correctIndex:1,explanation:"Isaías 53:4-6: 'Certamente ele tomou sobre si as nossas enfermidades... foi traspassado pelas nossas transgressões... e o Senhor fez cair sobre ele a iniquidade de nós todos.'",reference:"Isaías 53:4-6",category:.profetas,propheticMeaning:"O sofrimento vicário do Servo é o princípio da substituição penal — Cristo sofreu o que nós merecíamos, e nós recebemos o que ele merecia (2 Co 5:21). Esta é a essência do evangelho."),
QuizQuestion(id:415,question:"Qual profeta foi contemporâneo de Isaías e profetizou sobre Belém?",options:["Amós","Oséias","Miquéias","Naum"],correctIndex:2,explanation:"Miquéias foi contemporâneo de Isaías e profetizou sobre o nascimento do Messias em Belém (Mq 5:2), além de proclamar o famoso versículo 'O que o Senhor pede: justiça, amor e humildade' (Mq 6:8).",reference:"Miquéias 5:2; 6:8",category:.profetas,propheticMeaning:"Miquéias 6:8 — 'praticar a justiça, amar a misericórdia e andar humildemente com teu Deus' — é o resumo profético da vida cristã: o caráter de Cristo reproduzido em nós pelo Espírito."),
QuizQuestion(id:416,question:"O que profetizou Naum sobre a queda de Nínive?",options:["Que Nínive seria salva","Que Nínive seria completamente destruída","Que Nínive se tornaria capital do mundo","Que os assírios seriam convertidos"],correctIndex:1,explanation:"Naum profetizou a queda definitiva de Nínive, capital da Assíria — cumprida em 612 a.C. quando os babilônios e medos destruíram a cidade.",reference:"Naum 1:1; 3:7",category:.profetas,propheticMeaning:"Jonas trouxe Nínive ao arrependimento temporário, mas Naum anuncia que o arrependimento foi abandonado e o juízo definitivo chegará — Deus é paciente mas não compactua com a maldade permanente."),
QuizQuestion(id:417,question:"O que o profeta Sofonias anunciou?",options:["Apenas palavras de conforto","Julgamento do 'Dia do Senhor' sobre as nações e Judá","Que o exílio não viria","Profecias sobre o templo"],correctIndex:1,explanation:"Sofonias alterna entre terror do Dia do Senhor e promessa de redenção para o 'povo humilde e pobre' que confia em Deus.",reference:"Sofonias 3:17",category:.profetas,propheticMeaning:"Sofonias 3:17: 'O Senhor teu Deus está no meio de ti... exultará de alegria sobre ti; renovar-te-á no seu amor; regozijar-se-á sobre ti com júbilo' — prefigura a alegria do Pai com o filho que retorna (Lc 15:24)."),
QuizQuestion(id:418,question:"Qual é o chamado de Ageu aos que retornaram do exílio?",options:["Descansar após o retorno","Reconstruir o templo que estava em ruínas enquanto eles moravam em","Realizar reformas políticas","Evangelizar os outros povos"],correctIndex:1,explanation:"Ageu convocou os que retornaram do exílio a priorizar a casa de Deus sobre suas próprias casas — o templo havia estado em ruínas por 16 anos enquanto eles se estabeleciam.",reference:"Ageu 1:4-8",category:.profetas,propheticMeaning:"'Considerai o vosso caminho' (Ag 1:5,7) — o princípio profético de parar e avaliar prioridades. Buscar primeiro o Reino é a herança de Ageu para a espiritualidade de todos os tempos."),
QuizQuestion(id:419,question:"Qual profeta viu uma visão de cavaleiros em quatro cores em Zacarias 1 e 6?",options:["Ezequiel","Daniel","Zacarias","Isaías"],correctIndex:2,explanation:"Zacarias viu visões de cavaleiros montando cavalos de quatro cores — vermelho, negro, branco e malhado — patrulhando a terra, reaparecem em Apocalipse 6 como os quatro cavaleiros.",reference:"Zacarias 1:8-11; 6:1-8",category:.profetas,propheticMeaning:"Os quatro cavaleiros de Zacarias reaparecendo em Apocalipse 6 com os selos mostram a continuidade da visão profética — João recebe revelação que constrói sobre a revelação de Zacarias."),
QuizQuestion(id:420,question:"Qual é a última palavra de Deus no AT antes do silêncio de 400 anos?",options:["'Eis que enviarei o profeta Elias'","'Lembrai-vos da lei de Moisés... eis que enviarei o profeta Elias...","'Voltai a mim e eu voltarei a vós'","'O justo viverá pela sua fé'"],correctIndex:1,explanation:"Malaquias 4:4-6 fecha o AT com duplo apelo: lembrar a lei de Moisés e aguardar o novo Elias — precisamente o que João Batista seria, quebrando o silêncio 400 anos depois.",reference:"Malaquias 4:4-6; Lucas 1:17",category:.profetas,propheticMeaning:"O AT termina esperando por dois: Moisés (a lei) e Elias (os profetas) — exatamente quem aparece na Transfiguração com Jesus (Mt 17:3). O NT começa onde o AT parou."),
QuizQuestion(id:421,question:"O que foi a 'serpente de bronze' e como ela tipifica Cristo?",options:["Um ídolo de Israel","Moisés ergueu uma serpente de bronze no deserto","Uma decoração do templo","Uma armadilha para inimigos"],correctIndex:1,explanation:"Números 21:8-9: serpentes picavam Israel por desobediência; Deus ordenou serpente de bronze num poste — quem olhasse viveria. Jesus usou isso como tipo de si mesmo.",reference:"Números 21:8-9; João 3:14-15",category:.profetas,propheticMeaning:"João 3:14-15: 'Assim como Moisés levantou a serpente no deserto, assim importa que o Filho do Homem seja levantado, para que todo o que nele crer tenha a vida eterna.' A serpente de bronze é um dos tipos mais explicitamente cristológicos do AT."),
QuizQuestion(id:422,question:"O que foi o 'Dia da Expiação' em Levítico 16 e como ele tipifica Cristo?",options:["Uma festa de colheita","O sumo-sacerdote entrava no Santo dos Santos com sangue de bode e um","Uma celebração de vitória","O dia em que o povo descansava apenas"],correctIndex:1,explanation:"No Yom Kippur (Lv 16): um bode era sacrificado pelo pecado do povo; o segundo (bode expiatório/Azazel) recebia os pecados confessados e era solto no deserto.",reference:"Levítico 16:15-22; Hebreus 9:11-12",category:.profetas,propheticMeaning:"Cristo é ambos os bodes: ele foi sacrificado (pagando o preço) e também carregou nossos pecados para longe (Sl 103:12 — 'assim como o oriente dista do ocidente'). Hebreus 9 explica o cumprimento."),
QuizQuestion(id:423,question:"Qual é o significado da Arca da Aliança?",options:["Um baú para guardar tesouros","A caixa sagrada que continha as tábuas da lei","Uma arma de guerra de Israel","O local onde Salomão guardava ouro"],correctIndex:1,explanation:"A Arca da Aliança (Êx 25:10-22) continha as tábuas da lei, maná e a vara de Arão — era o trono de Deus entre os querubins, símbolo de sua presença.",reference:"Êxodo 25:10-22; Hebreus 9:4",category:.profetas,propheticMeaning:"A Arca com a propiciatória (lugar do sangue expiatório) sobre as tábuas da lei é tipo de Cristo — ele cumpriu a lei (tábuas) e seu sangue na propiciatória satisfez a justiça divina (1 Jo 2:2)."),
QuizQuestion(id:424,question:"O que simbolizava o véu do templo?",options:["A beleza do templo","A separação entre Deus e a humanidade pecadora","Uma cortina decorativa","A proteção do templo contra ladrões"],correctIndex:1,explanation:"O véu separava o lugar santo do Santo dos Santos (Ex 26:33) — barreira entre a presença santíssima de Deus e o povo pecador, transposta apenas pelo sumo-sacerdote na expiação anual.",reference:"Êxodo 26:33; Hebreus 9:7-8",category:.profetas,propheticMeaning:"Quando Jesus morreu, o véu rasgou-se de cima a baixo (Mt 27:51) — Deus rasgando a barreira da separação. Hebreus 10:19-20 explica: 'temos ousadia para entrar no lugar santíssimo pelo sangue de Jesus e pelo véu, isto é, pela sua carne.'"),
QuizQuestion(id:425,question:"O que significa 'propiciação' em teologia?",options:["Satisfação humana de Deus","A satisfação da ira justa de Deus contra o pecado","Uma cerimônia religiosa","Reconciliação sem julgamento"],correctIndex:1,explanation:"Propiciação (hilasmos) é a satisfação da justa ira de Deus pelo pecado. 1 João 2:2: 'ele mesmo é a propiciação pelos nossos pecados, e não somente pelos nossos, mas também pelos de todo o mundo.'",reference:"1 João 2:2; Romanos 3:25",category:.geral,propheticMeaning:"A propiciação distingue o evangelho cristão de toda religião humana — não humanos aplacando Deus através de obras, mas o próprio Deus provendo em Cristo a satisfação de sua própria justiça (Rm 3:26)."),
QuizQuestion(id:426,question:"Qual é a diferença entre 'propiciação' e 'expiação'?",options:["São palavras idênticas","Expiação foca na remoção do pecado e culpa (de nós)","Propiciação é apenas OT","Expiação é apenas NT"],correctIndex:1,explanation:"Expiação: cobertura/remoção do pecado (de nossa parte). Propiciação: apaziguamento da ira justa de Deus (do lado divino). Cristo realiza ambas na cruz.",reference:"Levítico 16:10; 1 João 2:2",category:.geral,propheticMeaning:"A cruz satisfaz tanto a necessidade humana (expiação — nosso pecado removido) quanto o requisito divino (propiciação — a justiça de Deus satisfeita). Deus é simultaneamente 'justo e justificador' (Rm 3:26)."),
QuizQuestion(id:427,question:"O que é a 'imputação' na teologia reformada?",options:["Atribuição falsa","A contagem ou reckoning","Uma forma de batismo","Um rito eclesiástico"],correctIndex:1,explanation:"Imputação é a transferência legal: nossos pecados foram contados como de Cristo na cruz; a perfeita obediência de Cristo é contada como nossa na justificação.",reference:"2 Coríntios 5:21; Romanos 4:22-24",category:.geral,propheticMeaning:"'Aquele que não conheceu pecado, por nós o fez pecado, para que nele nos tornemos justiça de Deus' (2 Co 5:21) — a troca maravilhosa: nossa culpa pelo seu crédito, nossa vergonha pela sua glória."),
QuizQuestion(id:428,question:"O que Paulo ensina sobre a glória de Deus em Romanos 11:33-36?",options:["A glória de Deus é compreensível","'Ó profundidade das riquezas","A glória de Deus depende das obras humanas","A glória de Deus é apenas para Israel"],correctIndex:1,explanation:"Romanos 11:33-36 é um hino de louvor à transcendência de Deus — após discutir os mistérios da eleição de Israel e gentios, Paulo explode em adoração.",reference:"Romanos 11:33-36",category:.geral,propheticMeaning:"Paulo terminando um argumento teológico complexo em adoração (Rm 11:33-36) é modelo: a teologia correta leva ao louvor, não apenas ao orgulho intelectual — 'a ele a glória para sempre.'"),
QuizQuestion(id:429,question:"O que significa 'kenosis' em relação a Cristo?",options:["A ressurreição de Cristo","O 'esvaziamento' de Cristo","A glorificação de Cristo","A ascensão de Cristo"],correctIndex:1,explanation:"Kenosis vem do grego kénoo (Fp 2:7) — Cristo se 'esvaziou' da manifestação gloriosa para assumir forma de servo humano, ainda sendo plenamente divino.",reference:"Filipenses 2:6-8",category:.geral,propheticMeaning:"A kenosis revela a humildade extrema de Deus — o Criador entrando na criação, o Eterno entrando no tempo, o Poderoso tornando-se vulnerável — o modelo supremo de humildade para a Igreja (Fp 2:5)."),
QuizQuestion(id:430,question:"O que é a 'exaltação' de Cristo em Filipenses 2?",options:["O batismo de Jesus","Após a kenosis, Deus o exaltou ao mais alto lugar","A Transfiguração","A Ascensão isolada"],correctIndex:1,explanation:"Fp 2:9-11: após a humilhação máxima (morte de cruz), Deus o exaltou ao máximo — todo joelho se dobrará e toda língua confessará que Jesus Cristo é Senhor.",reference:"Filipenses 2:9-11",category:.geral,propheticMeaning:"O padrão kenosis-exaltação é o padrão do Reino: 'quem se humilha será exaltado' (Mt 23:12). O caminho da glória passa pela cruz — para Cristo e para seus seguidores (Rm 8:17)."),
]
